var e=[{id:`L2_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 손님, 객차에서 난동을 피우시면 안 됩니다.`,JPN:` お客様、車内での騒動はお控えください。`,ENG:`You are not allowed to cause disruption on the train.`,TWN:`小姐，在列車中請勿滋事。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 지시에 따르지 않을 시에는 즉각 퇴장 조치하겠습니다.`,JPN:` 指示に従っていただけない場合、即時ご退場いただきます。`,ENG:`You will be escorted out if you do not abide by the rules.`,TWN:`要是你再不配合，我們會強行趕你下車。`},stage:{bg:`TRAIL`,slots:{L:null,C:null,R:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 달리는 열차 밖으로 집어던지기라도 하려고? 무서워라.`,JPN:` 走っている列車の外に放り出しでもするつもり？　あー怖い怖い。`,ENG:`What, you're gonna throw me out of this moving train? How frightening.`,TWN:`意思是要把我扔出行進的列車外嗎？我好怕喔。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 죽여도 죽여도 끝이 없네. 가뜩이나 움직임도 날래서 상대하기 벅찬데.`,JPN:` 倒しても倒してもキリがない。動きもすばしっこくて、倒しづらいし、最悪。`,ENG:`There's no end to them. It's hard enough that they're so nimble.`,TWN:`怎麼殺都殺不完，而且移動速度又很快，不太好對付呢。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 계속 싸우는 건 자살 행위야. 수류탄이라도 있으면 좋을 텐데.`,JPN:` このまま戦い続けるのは自殺行為よね。手榴弾でもあればなあ。`,ENG:`There's no point in continuing this fight. I wish I had a grenade or something.`,TWN:`再打下去也是自取滅亡，真希望有手榴彈。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 퇴로는…… 뒷객차로 넘어가는 것뿐인가?`,JPN:` 退路は……後ろの客車に逃げるしかないか？`,ENG:`Is... the passenger car on the back my only escape route?`,TWN:`後面的車廂……是唯一的退路嗎？`},stage:{bg:`TRAIL`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 손님, 지정된 좌석에서 이탈하지 말아 주십시오.`,JPN:` お客様、指定のお座席を離れないでください。`,ENG:`Do not leave your designated seat.`,TWN:`小姐，請勿離開你的座位。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 도망치려고 해도 의미없는 행동입니다. `,JPN:` 逃げようとするのは、無駄な行為です。 `,ENG:`Your attempt to escape is pointless.`,TWN:`請不要做無謂的嘗試，你是逃不掉的。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 그거야 해 보지 않고선 모르지!`,JPN:` そんなのやってみなくちゃわからないでしょ！`,ENG:`You never know until you try!`,TWN:`不試試看怎麼知道！`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:null,text:{KOREA:` `},stage:{bg:`TRAIL`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 큭……! 여기에도 숨어 있었어?`,JPN:` くっ……！　ここにも隠れていたか？`,ENG:`Kgh...! There were more hiding here...!`,TWN:` 唔……！這裡也有？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 진정하십시오, 손님.`,JPN:` 落ち着いてください、お客様。`,ENG:`Please, keep your composure.`,TWN:`小姐，請你冷靜點。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 다리가 불편하십니까? 절단해 드릴까요?`,JPN:` 脚にご不調でも？　切断をお手伝いいたしましょうか？`,ENG:`Are your legs bothering you? Would you like them to be removed?`,TWN:`你的腳不舒服嗎？需要我幫你截肢嗎？`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:` 가까이 오지 마!`,JPN:` こっちに来るな！`,ENG:`Get away from me!`,TWN:`不要過來！`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 움직이기 어려우시면 저희가 부축해 드리겠습니다.`,JPN:` お一人で動けないのでしたら、我々が席までお連れいたします。`,ENG:`We shall assist you if you have trouble moving.`,TWN:`不方便移動的話我們可以扶你。`},stage:{bg:`TRAIL`,slots:{L:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L30_1`,type:`dialog`,speaker:`MEMBER_HARMONY_NULL_NULL`,text:{KOREA:` 지정된 좌석으로 돌아가서 안정을 취하십시오.`,JPN:` 指定のお座席にお戻りになり、安静になさってください。`,ENG:`Please return to your designated seat and rest.`,TWN:`請回到你的座位保持安靜。`},stage:{bg:`TRAIL`,slots:{L:null,C:{char_id:`MEMBER_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};